        long prefixSum = 0;
        long dp = 0;
        Map<Long, Long> modMap = new HashMap<>();
        modMap.put(0, 0L);
        for (long num : nums) {
            prefixSum += num;
            long currentMod = prefixSum % k;
            long maxVal = modMap.getOrDefault(currentMod, Long.MIN_VALUE);
            long candidate = maxVal + prefixSum;
            long new_dp = Math.max(dp, candidate);
            dp = new_dp;
            long currentEntry = dp - prefixSum;
            modMap.put(currentMod, Math.max(modMap.getOrDefault(currentMod, Long.MIN_VALUE), currentEntry));
        }
        return prefixSum - dp;
    }
